This binary search sometimes crashes with an IndexError. Find the exact failure case and provide the corrected function:

def binary_search(arr, target):
    lo, hi = 0, len(arr)
    while lo < hi:
        mid = (lo + hi) // 2
        if arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid
    return lo if arr[lo] == target else -1

